css:
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --bg:#0a0a0c;
  --surface:#1a1a1d;
  --surface-2:#222226;
  --text:#fff;
  --text-dim:#9c9ca1;
  --text-mute:#5e5e63;
  --green:#5DBF6F;
  --red:#E5484D;
  --purple:#BBAEFC;
  --safe-top:env(safe-area-inset-top, 0px);
  --safe-bottom:env(safe-area-inset-bottom, 0px);
}
html,body{
  margin:0;padding:0;
  width:100%;
  min-height:100%;
  min-height:100vh;
  min-height:-webkit-fill-available;
  height:100%;
  height:-webkit-fill-available;
  height:100vh;
  height:calc(var(--vh, 1vh) * 100);
  background:#0a0a0c;color:var(--text);
  font-family:-apple-system,BlinkMacSystemFont,'SF Pro Display','Inter','Segoe UI',sans-serif;
  -webkit-font-smoothing:antialiased;overscroll-behavior:none;overflow:hidden;touch-action:pan-y;overflow-x:hidden;
}
/* Full-screen UI - no zoom scaling */
button{background:none;border:none;color:inherit;font:inherit;cursor:pointer;-webkit-tap-highlight-color:transparent}
img{display:block;max-width:100%}

.app{
  position:fixed;
  inset:0;
  max-width:100vw;
  margin:0 auto;
  width:100%;
  height:100%;
  height:-webkit-fill-available;
  height:100vh;
  height:calc(var(--vh, 1vh) * 100);
  min-height:-webkit-fill-available;
  overflow:hidden;
  background:#0a0a0c;
  padding-left:env(safe-area-inset-left);
  padding-right:env(safe-area-inset-right);
}

.scrollable{
  position:relative;z-index:2;
  height:100%;width:100%;overflow-y:auto;overflow-x:hidden;-webkit-overflow-scrolling:touch;
  scrollbar-width:none;padding-bottom:140px;
  overscroll-behavior:none;
  background:#0a0a0c;
  touch-action:pan-y;
  transform:translateZ(0);
  will-change:scroll-position;
  contain:layout paint style;
}
.scrollable::-webkit-scrollbar{display:none}
img{content-visibility:auto;}

#ptr-wrapper{position:relative;z-index:1;isolation:isolate}
.bg-glow{
  position:absolute;top:0;left:0;right:0;height:560px;
  background:url('/assets/bg-purple.jpeg?v=2') no-repeat top center;
  background-size:100% auto;
  pointer-events:none;z-index:-1;
}
.bg-glow::after{
  content:"";position:absolute;inset:0;
  background:linear-gradient(180deg, rgba(10,10,12,0) 0%, rgba(10,10,12,0) 38%, rgba(10,10,12,0.75) 65%, #0a0a0c 92%);
}
.scrollable::-webkit-scrollbar{display:none}

/* Spinner (PTR) */
.spinner{font-size:36px;position:relative;display:inline-block;width:1em;height:1em}
.spinner.center{position:absolute;left:50%;top:65px;transform:translateX(-50%) scale(0);opacity:0;z-index:999;pointer-events:none}
.spinner-blade{position:absolute;left:.43em;bottom:0;width:.084em;height:.2777em;border-radius:.0655em;background-color:transparent;transform-origin:center -0.11em;animation:spinner-fade 1s infinite linear}
.spinner-blade:nth-child(1){transform:rotate(0)}
.spinner-blade:nth-child(2){transform:rotate(45deg);animation-delay:.125s}
.spinner-blade:nth-child(3){transform:rotate(90deg);animation-delay:.25s}
.spinner-blade:nth-child(4){transform:rotate(135deg);animation-delay:.375s}
.spinner-blade:nth-child(5){transform:rotate(180deg);animation-delay:.5s}
.spinner-blade:nth-child(6){transform:rotate(225deg);animation-delay:.625s}
.spinner-blade:nth-child(7){transform:rotate(270deg);animation-delay:.75s}
.spinner-blade:nth-child(8){transform:rotate(315deg);animation-delay:.875s}
@keyframes spinner-fade{0%{background-color:#fff}100%{background-color:transparent}}

/* HEADER */
.header{
  display:flex;justify-content:space-between;align-items:center;
  padding:calc(var(--safe-top) + 12px) 18px 18px;
  position:sticky;top:0;z-index:10;
}
.header::before{
  content:"";position:absolute;left:0;right:0;top:-200px;bottom:0;
  backdrop-filter:blur(10px);-webkit-backdrop-filter:blur(10px);
  background:linear-gradient(180deg, rgba(10,10,12,0.35) 0%, rgba(10,10,12,0.18) 80%, rgba(10,10,12,0) 100%);
  -webkit-mask-image:linear-gradient(180deg, #000 0%, #000 85%, transparent 100%);
  mask-image:linear-gradient(180deg, #000 0%, #000 85%, transparent 100%);
  pointer-events:none;z-index:-1;
}
.header-right{display:flex;gap:10px;align-items:center}
.circle-btn{
  width:42px;height:42px;border-radius:50%;
  background:rgba(255,255,255,0.08);
  display:flex;align-items:center;justify-content:center;
  position:relative;color:#fff;
  backdrop-filter:blur(12px);-webkit-backdrop-filter:blur(12px);
}
.circle-btn svg{width:20px;height:20px}
.circle-btn.has-dot::after{
  content:"";position:absolute;top:9px;right:10px;
  width:7px;height:7px;border-radius:50%;background:#E5484D;
  border:1.5px solid rgba(20,18,30,0.8);
}

/* BALANCE */
.balance-section{text-align:center;padding:34px 20px 6px}
.balance-amount{
  font-size:54px;font-weight:600;letter-spacing:-1.8px;
  line-height:1;color:#fff;
}
.balance-amount .cents{color:rgba(255,255,255,0.35);font-weight:700}
.balance-pill{
  display:inline-flex;align-items:center;gap:6px;
  margin-top:18px;padding:8px 14px;
  background:rgba(255,255,255,0.06);
  border:1px solid rgba(255,255,255,0.08);
  border-radius:100px;
  font-size:14px;font-weight:500;color:#fff;
  backdrop-filter:blur(8px);
}
.bp-pct{color:var(--green);font-weight:600}
.bp-pct.down{color:var(--red)}
.bp-dot{color:rgba(255,255,255,0.45)}
.bp-period{color:#fff}
.bp-arrow{color:rgba(255,255,255,0.55);margin-left:2px;font-size:16px;line-height:1}

/* QUICK ACTIONS */
.quick-actions{
  display:flex;gap:10px;padding:30px 16px 0;
}
.qa-btn{
  flex:1;display:flex;flex-direction:column;align-items:center;gap:8px;
  background:rgba(28,28,32,0.85);
  border:1px solid rgba(255,255,255,0.04);
  border-radius:14px;
  padding:18px 0 16px;color:#fff;
  transition:transform .15s ease, background .15s ease;
}
.qa-btn:active{transform:scale(0.97);background:rgba(40,40,46,0.9)}
.qa-btn svg{width:22px;height:22px;opacity:.95}
.qa-btn .qa-icon-img{width:62px;height:62px;object-fit:contain;opacity:.95;margin:-20px 0}
.qa-btn span{font-size:14px;font-weight:500}

/* PROMO CAROUSEL */
.promo-carousel-wrap{padding:18px 0 0;}
.promo-carousel{
  display:flex;gap:10px;
  padding:0 16px;
  overflow-x:auto;scrollbar-width:none;
  scroll-snap-type:x mandatory;
  -webkit-overflow-scrolling:touch;
}
.promo-carousel::-webkit-scrollbar{display:none}
.promo-card{
  position:relative;
  flex:0 0 100%;
  scroll-snap-align:center;
  border-radius:14px;
  overflow:hidden;
  height:78px;
  background:#1a1a1f;
  display:flex;align-items:center;
  padding:0 16px;gap:12px;
}
.promo-card .pc-text{min-width:0;flex:1;padding-right:60px}
.promo-card .pc-title{
  font-size:15px;font-weight:700;color:#fff;line-height:1.2;
  white-space:nowrap;overflow:hidden;text-overflow:ellipsis;
}
.promo-card .pc-sub{
  font-size:12.5px;color:rgba(255,255,255,0.5);margin-top:3px;
  white-space:nowrap;overflow:hidden;text-overflow:ellipsis;
}
.promo-card .pc-logo{
  position:absolute;right:30px;top:50%;transform:translateY(-50%);
  width:64px;height:64px;object-fit:contain;
}
.promo-card .pc-close{
  position:absolute;top:8px;right:8px;
  width:20px;height:20px;color:rgba(255,255,255,0.55);
  display:flex;align-items:center;justify-content:center;padding:0;
}
.promo-card .pc-close svg{width:14px;height:14px}

/* OFFER ROW */
.offer-row{
  display:flex;gap:10px;padding:4px 16px 0;
  overflow-x:auto;scrollbar-width:none;
  scroll-snap-type:x mandatory;-webkit-overflow-scrolling:touch;
}
.offer-row::-webkit-scrollbar{display:none}
.offer-card{
  position:relative;flex:0 0 44%;
  background:#1a1a1f;border-radius:16px;
  padding:12px 12px 14px;scroll-snap-align:start;
  display:flex;flex-direction:column;
  border:1px solid rgba(255,255,255,0.04);
}
.offer-chip{
  align-self:flex-start;
  background:rgba(187,174,252,0.18);color:#BBAEFC;
  font-size:12px;font-weight:700;
  padding:4px 9px;border-radius:6px;
}
.offer-close{
  position:absolute;top:10px;right:10px;
  width:22px;height:22px;color:rgba(255,255,255,0.7);
  display:flex;align-items:center;justify-content:center;padding:0;
}
.offer-close svg{width:14px;height:14px}
.offer-img{
  width:100%;height:110px;object-fit:contain;margin:8px 0;
}
.offer-name{
  font-size:13.5px;font-weight:600;color:#fff;text-align:center;
  line-height:1.2;
}
.promo-dots{
  display:flex;justify-content:center;gap:6px;
  padding:10px 0 0;
}
.promo-dots .dot{
  width:6px;height:6px;border-radius:50%;
  background:rgba(255,255,255,0.25);
  transition:background .2s ease;
}
.promo-dots .dot.active{background:rgba(255,255,255,0.85)}

/* SECTION HEADER */
.section-header{
  display:flex;align-items:center;gap:6px;
  padding:40px 18px 16px;
  font-size:20px;font-weight:700;letter-spacing:-.3px;
}
.section-chevron{color:#fff;font-size:24px;line-height:.7;font-weight:400}

/* EXPLORE ROW */
.explore-row{
  display:flex;gap:10px;
  padding:0 16px;
  overflow-x:auto;scrollbar-width:none;
  scroll-snap-type:x mandatory;
}
.explore-row::-webkit-scrollbar{display:none}
.explore-card{
  flex:0 0 105px;height:125px;
  background:rgba(28,28,32,0.85);
  border:1px solid rgba(255,255,255,0.04);
  border-radius:16px;
  display:flex;flex-direction:column;align-items:center;justify-content:center;
  padding:14px 8px;scroll-snap-align:start;
}
.explore-card.coin-card{justify-content:flex-start;gap:10px;padding-top:18px}
.explore-card.image-card{padding:0;overflow:hidden}
.explore-card.image-card img{width:100%;height:100%;object-fit:cover;display:block}
.cc-logo{
  width:46px;height:46px;border-radius:50%;
  display:flex;align-items:center;justify-content:center;
  overflow:hidden;background:#2a2a30;
}
.cc-logo img{width:100%;height:100%;object-fit:cover}
.cc-name{font-size:14px;font-weight:600;color:#fff}
.cc-pct{font-size:13px;font-weight:500;color:var(--green);margin-top:auto}
.cc-pct.up{color:var(--green)}
.cc-pct.down{color:var(--red)}

.mood-gauge{position:relative;width:62px;height:38px;margin-bottom:4px}
.mood-gauge svg{width:100%;height:100%}
.mood-num{position:absolute;left:0;right:0;bottom:0;text-align:center;font-size:18px;font-weight:700;color:#fff}
.mood-label{font-size:14px;font-weight:600;color:#fff;margin-top:6px}
.mood-state{font-size:13px;color:var(--green);font-weight:500;margin-top:2px}

/* SEGMENTED TABS */
.segment-control{
  display:flex;margin:28px 16px 8px;
  background:rgba(28,28,32,0.85);
  border:1px solid rgba(255,255,255,0.04);
  border-radius:14px;padding:5px;
}
.segment-btn{
  flex:1;padding:12px;border-radius:10px;
  font-size:15px;font-weight:600;color:var(--text-mute);
  transition:all .18s ease;
}
.segment-btn.active{background:rgba(60,60,68,0.85);color:#fff}

/* ASSET LIST */
.asset-list{padding:6px 16px}
.asset-item{
  display:flex;align-items:center;justify-content:space-between;
  padding:14px 0;
}
.asset-left{display:flex;align-items:center;gap:14px;min-width:0;flex:1}
.asset-logo{
  flex-shrink:0;width:42px;height:42px;border-radius:50%;
  overflow:hidden;background:#2a2a30;
}
.asset-logo img{width:100%;height:100%;object-fit:cover}
.asset-info{min-width:0;flex:1}
.asset-name{font-size:16px;font-weight:600;color:#fff}
.asset-sub-text{font-size:13px;color:var(--text-dim);margin-top:2px}
.asset-right{flex-shrink:0;text-align:right}
.asset-value{font-size:16px;font-weight:600;color:#fff}
.asset-change-pct{font-size:13px;font-weight:500;margin-top:2px;color:var(--green)}
.asset-change-pct.down{color:var(--red)}

/* BOTTOM NAV */
.bottom-nav{
  position:fixed;left:0;right:0;bottom:calc(8px + var(--safe-bottom));
  max-width:100vw;margin:0 auto;
  padding:0 14px;
  display:flex;align-items:center;gap:10px;
  z-index:50;pointer-events:none;
}
.nav-pill{
  flex:1;display:flex;align-items:center;justify-content:space-around;
  background:rgba(20,20,24,0.85);
  backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);
  border:1px solid rgba(255,255,255,0.06);
  border-radius:32px;padding:10px 4px;
  pointer-events:auto;
  box-shadow:0 8px 24px rgba(0,0,0,0.4);
}
.nav-btn{
  flex:1;display:flex;flex-direction:column;align-items:center;gap:3px;
  color:var(--text-dim);padding:6px 4px;border-radius:18px;
  font-size:11px;font-weight:500;
  transition:color .15s ease, background .15s ease;
}
.nav-btn svg{width:22px;height:22px}
.nav-btn .nav-icon-img{width:35px;height:35px;object-fit:contain;margin:-6px 0}
.circle-btn .header-device-img{width:45px;height:45px;border-radius:50%;object-fit:cover;margin:-2px}
.nav-btn.active{color:#fff;background:rgba(255,255,255,0.06)}
.nav-spark{
  width:46px;height:46px;border-radius:50%;
  background:rgba(20,20,24,0.85);
  backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);
  border:1px solid rgba(255,255,255,0.06);
  display:flex;align-items:center;justify-content:center;
  color:#fff;pointer-events:auto;flex-shrink:0;
  box-shadow:0 8px 24px rgba(0,0,0,0.4);
}
.nav-spark svg{width:22px;height:22px;opacity:.85}

/* SETTINGS */
.settings-overlay{position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:200;display:flex;align-items:flex-end;opacity:0;pointer-events:none;transition:opacity .25s ease}
.settings-overlay.open{opacity:1;pointer-events:all}
.settings-panel{width:100%;max-width:100vw;margin:0 auto;background:#1a1a1d;border-radius:18px 18px 0 0;padding:10px 14px calc(10px + var(--safe-bottom));transform:translateY(100%);transition:transform .3s cubic-bezier(.25,1,.5,1);max-height:88dvh;display:flex;flex-direction:column}
.settings-overlay.open .settings-panel{transform:translateY(0)}
.settings-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;flex:none}
.settings-title{font-size:13px;font-weight:700;color:#fff}
.settings-close{color:var(--text-dim);font-size:16px;padding:0 4px}
.settings-body{flex:1 1 auto;overflow-y:auto;-webkit-overflow-scrolling:touch;padding-right:2px;scrollbar-width:thin}
.settings-body::-webkit-scrollbar{width:4px}
.settings-body::-webkit-scrollbar-thumb{background:rgba(255,255,255,.12);border-radius:4px}
.settings-row{display:flex;align-items:center;gap:8px;padding:4px 0;border-bottom:1px solid rgba(255,255,255,.05)}
.settings-row label{font-size:11px;font-weight:600;color:var(--text-dim);width:52px;flex-shrink:0}
.settings-row input,.settings-row select{flex:1;background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.1);border-radius:7px;color:#fff;font-size:12px;padding:5px 9px;font-family:inherit;text-align:right;-webkit-appearance:none;appearance:none;outline:0}
.settings-row input[type=checkbox]{flex:0 0 auto;width:16px;height:16px;padding:0;background:0 0;appearance:auto;accent-color:var(--purple)}
.settings-divider{height:3px}
.settings-confirm{width:100%;margin-top:10px;padding:9px;background:var(--purple);border-radius:9px;color:#0a0a0c;font-size:13px;font-weight:700}


.crypto-header{display:flex;align-items:baseline;gap:6px;padding:32px 18px 8px}

/* ASSETS / ACCOUNTS TABS */
.aa-tabs{
  display:flex;margin:24px 16px 10px;
  background:transparent;
  border:1px solid rgba(255,255,255,0.08);
  border-radius:100px;padding:3px;gap:3px;
}
.aa-tab{
  flex:1;padding:8px 0;border-radius:100px;
  font-size:14px;font-weight:600;color:#fff;
  transition:background .18s ease;
}
.aa-tab.active{background:rgba(60,60,68,0.6);border:1px solid rgba(255,255,255,0.08)}

/* ACCOUNTS */
.accounts-list{padding:6px 16px 0}
.account-item{
  display:flex;align-items:center;justify-content:space-between;
  padding:14px 0;gap:12px;
}
.acc-left{min-width:0;flex:1}
.acc-name{
  font-size:17px;font-weight:700;color:#fff;
  background:transparent;border:none;outline:none;padding:0;margin:0;
  font-family:inherit;width:100%;
}
.acc-name:focus{outline:1px solid rgba(187,174,252,0.5);border-radius:4px}
.acc-sub{display:flex;align-items:center;gap:6px;margin-top:3px}
.acc-addr{font-size:13px;color:var(--text-dim)}
.acc-coin-ic{width:16px;height:16px;border-radius:50%;object-fit:cover;flex-shrink:0}
.acc-value{font-size:17px;font-weight:700;color:#fff;flex-shrink:0}
.accounts-add,.accounts-see-all{
  display:flex;align-items:center;justify-content:space-between;
  width:calc(100% - 32px);margin:14px 16px 0;
  padding:18px 18px;border-radius:14px;
  border:1px solid rgba(255,255,255,0.12);
  background:transparent;color:#fff;font-size:15px;font-weight:600;
}
.accounts-see-all{justify-content:center;margin-bottom:10px}
.aa-plus{font-size:22px;font-weight:400;line-height:1}
.ch-title{font-size:22px;font-weight:700;letter-spacing:-.4px;color:#fff}
.ch-count{font-size:18px;font-weight:600;color:var(--text-mute)}
.ch-chevron{font-size:22px;color:#fff;line-height:.7;margin-left:2px;align-self:center}
.asset-dash{font-size:18px;color:var(--text-mute);font-weight:400}
.text-xs{font-size:12px}
.text-sm{font-size:14px}
.font-thin{font-weight:100}
.border-2{border:2px solid rgba(255,255,255,0.1);border-radius:16px}

/* FOR YOU */
.foryou-header{margin-top:18px}
.foryou-row{
  display:flex;gap:10px;overflow-x:auto;overflow-y:hidden;
  scroll-snap-type:x mandatory;-webkit-overflow-scrolling:touch;
  padding:0 16px 4px;margin:0 -16px;
}
.foryou-row::-webkit-scrollbar{display:none}
.foryou-card{
  position:relative;flex:0 0 78%;height:172px;border-radius:20px;
  background-color:#1a1a1d;background-size:cover;background-position:center;
  padding:14px;display:flex;flex-direction:column;justify-content:space-between;
  scroll-snap-align:start;overflow:hidden;
}
.foryou-card::after{
  content:"";position:absolute;inset:0;
  background:linear-gradient(180deg,rgba(0,0,0,0.05) 0%,rgba(0,0,0,0.55) 100%);
  pointer-events:none;
}
.foryou-card > *{position:relative;z-index:1}
.foryou-close{
  position:absolute;top:10px;right:10px;width:26px;height:26px;
  display:flex;align-items:center;justify-content:center;
  background:rgba(20,20,22,0.55);border-radius:50%;color:#fff;z-index:2;
  backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);
}
.foryou-close svg{width:13px;height:13px}
.foryou-chip{
  align-self:flex-start;background:#BBAEFC;color:#1a1a1d;
  font-size:12px;font-weight:600;padding:5px 10px;border-radius:8px;
  margin-top:auto;
}
.foryou-title{
  color:#fff;font-size:18px;font-weight:600;line-height:1.2;
  letter-spacing:-0.01em;margin-top:8px;
}

/* TRANSACTION HISTORY */
.txn-section{padding:8px 16px 0;margin-top:14px}
.txn-heading{
  font-size:12px;font-weight:600;color:var(--text-dim);
  letter-spacing:.12em;padding:24px 2px 12px;
}
.txn-date-pill{
  background:#161618;border-radius:12px;
  padding:14px 16px;font-size:13px;color:var(--text-dim);
  margin:14px 0 10px;
}
.txn-row{
  display:flex;align-items:center;gap:14px;padding:14px 0;
}
.txn-icon{
  flex-shrink:0;width:46px;height:46px;border-radius:12px;
  border:1px solid rgba(255,255,255,.18);
  display:flex;align-items:center;justify-content:center;color:#fff;
}
.txn-icon svg{width:18px;height:18px}
.txn-mid{flex:1;min-width:0}
.txn-name{font-size:16px;font-weight:700;color:#fff}
.txn-sub{font-size:13px;color:var(--text-dim);margin-top:2px}
.txn-right{text-align:right;flex-shrink:0}
.txn-amt{font-size:15.5px;font-weight:700;color:#fff}
